383	void RimeWithWeaselHandler::OnNotify(void* context_object,
384	                                     uintptr_t session_id,
385	                                     const char* message_type,
386	                                     const char* message_value) {
387	  // may be running in a thread when deploying rime
388	  RimeWithWeaselHandler* self =
389	      reinterpret_cast<RimeWithWeaselHandler*>(context_object);
390	  if (!self || !message_type || !message_value)
391	    return;
392	  std::lock_guard<std::mutex> lock(m_notifier_mutex);
393	  m_message_type = message_type;
394	  m_message_value = message_value;
395	  if (RIME_API_AVAILABLE(rime_api, get_state_label) &&
396	      !strcmp(message_type, "option")) {
397	    Bool state = message_value[0] != '!';
398	    const char* option_name = message_value + !state;
399	    m_option_name = option_name;
400	    const char* state_label =
401	        rime_api->get_state_label(session_id, option_name, state);
402	    if (state_label) {
403	      m_message_label = std::string(state_label);
404	    }
405	  }
406	}
