408	void RimeWithWeaselHandler::_ReadClientInfo(WeaselSessionId ipc_id,
409	                                            LPWSTR buffer) {
410	  std::string app_name;
411	  // parse request text
412	  wbufferstream bs(buffer, WEASEL_IPC_BUFFER_LENGTH);
413	  std::wstring line;
414	  while (bs.good()) {
415	    std::getline(bs, line);
416	    if (!bs.good())
417	      break;
418	    // file ends
419	    if (line == L".")
420	      break;
421	    const std::wstring kClientAppKey = L"session.client_app=";
422	    if (starts_with(line, kClientAppKey)) {
423	      std::wstring lwr = line;
424	      to_lower(lwr);
425	      app_name = wtou8(lwr.substr(kClientAppKey.length()));
426	    }
427	  }
428	  SessionStatus& session_status = get_session_status(ipc_id);
429	  RimeSessionId session_id = session_status.session_id;
430	  // set app specific options
431	  if (!app_name.empty()) {
432	    rime_api->set_property(session_id, "client_app", app_name.c_str());
433	
434	    auto it = m_app_options.find(app_name);
435	    if (it != m_app_options.end()) {
436	      AppOptions& options(m_app_options[it->first]);
437	      for (const auto& pair : options) {
438	        DLOG(INFO) << "set app option: " << pair.first << " = " << pair.second;
439	        rime_api->set_option(session_id, pair.first.c_str(), Bool(pair.second));
440	      }
441	    }
442	  }
443	  // inline preedit
444	  bool inline_preedit = session_status.style.inline_preedit;
445	  rime_api->set_option(session_id, "inline_preedit", Bool(inline_preedit));
446	  // show soft cursor on weasel panel but not inline
447	  rime_api->set_option(session_id, "soft_cursor", Bool(!inline_preedit));
448	}
