518	void RimeWithWeaselHandler::_UpdateUI(WeaselSessionId ipc_id) {
519	  // if m_ui nullptr, _UpdateUI meaningless
520	  if (!m_ui)
521	    return;
522	
523	  Status& weasel_status = m_ui->status();
524	  Context weasel_context;
525	
526	  RimeSessionId session_id = to_session_id(ipc_id);
527	
528	  if (ipc_id == 0)
529	    weasel_status.disabled = m_disabled;
530	
531	  _GetStatus(weasel_status, ipc_id, weasel_context);
532	
533	  SessionStatus& session_status = get_session_status(ipc_id);
534	  if (rime_api->get_option(session_id, "inline_preedit"))
535	    session_status.style.client_caps |= INLINE_PREEDIT_CAPABLE;
536	  else
537	    session_status.style.client_caps &= ~INLINE_PREEDIT_CAPABLE;
538	
539	  if (!_ShowMessage(weasel_context, weasel_status)) {
540	    m_ui->Hide();
541	    m_ui->Update(weasel_context, weasel_status);
542	  }
543	
544	  _RefreshTrayIcon(session_id, _UpdateUICallback);
545	
546	  {
547	    std::lock_guard<std::mutex> lock(m_notifier_mutex);
548	    m_message_type.clear();
549	    m_message_value.clear();
550	    m_message_label.clear();
551	    m_option_name.clear();
552	  }
553	}
554	
555	void RimeWithWeaselHandler::_LoadSchemaSpecificSettings(
556	    WeaselSessionId ipc_id,
557	    const std::string& schema_id) {
558	  if (!m_ui)
559	    return;
560	  RimeConfig config;
561	  if (!rime_api->schema_open(schema_id.c_str(), &config))
562	    return;
563	  _UpdateShowNotifications(&config);
564	  m_ui->style() = m_base_style;
565	  _UpdateUIStyle(&config, m_ui, false);
566	  SessionStatus& session_status = get_session_status(ipc_id);
567	  session_status.style = m_ui->style();
568	  UIStyle& style = session_status.style;
569	  // load schema color style config
570	  const int BUF_SIZE = 255;
571	  char buffer[BUF_SIZE + 1] = {0};
572	  const auto update_color_scheme = [&]() {
573	    std::string color_name(buffer);
574	    RimeConfigIterator preset = {0};
575	    if (rime_api->config_begin_map(
576	            &preset, &config, ("preset_color_schemes/" + color_name).c_str())) {
577	      _UpdateUIStyleColor(&config, style, color_name);
578	      rime_api->config_end(&preset);
579	    } else {
580	      RimeConfig weaselconfig;
581	      if (rime_api->config_open("weasel", &weaselconfig)) {
582	        _UpdateUIStyleColor(&weaselconfig, style, color_name);
583	        rime_api->config_close(&weaselconfig);
584	      }
585	    }
586	  };
587	  const char* key =
588	      m_current_dark_mode ? "style/color_scheme_dark" : "style/color_scheme";
589	  if (rime_api->config_get_string(&config, key, buffer, BUF_SIZE))
590	    update_color_scheme();
591	  // load schema icon start
592	  {
593	    const auto load_icon = [](RimeConfig& config, const char* key1,
594	                              const char* key2) {
595	      const auto user_dir = WeaselUserDataPath();
596	      const auto shared_dir = WeaselSharedDataPath();
597	      const int BUF_SIZE = 255;
598	      char buffer[BUF_SIZE + 1] = {0};
599	      if (rime_api->config_get_string(&config, key1, buffer, BUF_SIZE) ||
600	          (key2 != NULL &&
601	           rime_api->config_get_string(&config, key2, buffer, BUF_SIZE))) {
602	        auto resource = u8tow(buffer);
603	        if (fs::is_regular_file(user_dir / resource))
604	          return (user_dir / resource).wstring();
605	        else if (fs::is_regular_file(shared_dir / resource))
606	          return (shared_dir / resource).wstring();
607	      }
608	      return std::wstring();
609	    };
610	    style.current_zhung_icon =
611	        load_icon(config, "schema/icon", "schema/zhung_icon");
612	    style.current_ascii_icon = load_icon(config, "schema/ascii_icon", NULL);
613	    style.current_full_icon = load_icon(config, "schema/full_icon", NULL);
614	    style.current_half_icon = load_icon(config, "schema/half_icon", NULL);
615	  }
616	  // load schema icon end
617	  rime_api->config_close(&config);
618	}
