937	// Blend foreground and background ARGB colors taking alpha into account.
938	// Returns an ABGR COLORREF with premultiplied alpha blended result.
939	static inline COLORREF blend_colors(COLORREF fcolor, COLORREF bcolor) {
940	  // Extract ARGB channels from both colors.
941	  BYTE fA = (fcolor >> 24) & 0xFF;
942	  BYTE fB = (fcolor >> 16) & 0xFF;
943	  BYTE fG = (fcolor >> 8) & 0xFF;
944	  BYTE fR = fcolor & 0xFF;
945	  BYTE bA = (bcolor >> 24) & 0xFF;
946	  BYTE bB = (bcolor >> 16) & 0xFF;
947	  BYTE bG = (bcolor >> 8) & 0xFF;
948	  BYTE bR = bcolor & 0xFF;
949	  // Convert alpha to [0,1]
950	  float fAlpha = fA / 255.0f;
951	  float bAlpha = bA / 255.0f;
952	  // Result alpha
953	  float retAlpha = fAlpha + (1 - fAlpha) * bAlpha;
954	  if (retAlpha <= 1e-6f) {
955	    // Fully transparent result — return background unchanged as fallback.
956	    return bcolor;
957	  }
958	  auto mix = [&](float fc, float bc) -> BYTE {
959	    return static_cast<BYTE>((fc * fAlpha + bc * bAlpha * (1 - fAlpha)) /
960	                             retAlpha);
961	  };
962	  BYTE retR = mix(fR, bR);
963	  BYTE retG = mix(fG, bG);
964	  BYTE retB = mix(fB, bB);
965	  BYTE outA = static_cast<BYTE>(retAlpha * 255.0f);
966	  return (static_cast<COLORREF>(outA) << 24) | (retB << 16) | (retG << 8) |
967	         retR;
968	}
969	// parse color value, with fallback value
970	static Bool _RimeGetColor(RimeConfig* config,
971	                          const std::string& key,
972	                          int& value,
973	                          const ColorFormat& fmt,
974	                          const unsigned int& fallback) {
975	  char color[256] = {0};
976	  if (!rime_api->config_get_string(config, key.c_str(), color, 256)) {
977	    value = fallback;
978	    return False;
979	  }
980	  const auto color_str = std::string(color);
981	  // adjudge if str is 0x 0X # hex color format, return trimmed hex part
982	  // out part is 6 or 8 length hex string without white space
983	  const auto parse_color_code = [](const std::string& str, std::string& out) {
984	    if (str.empty())
985	      return false;
986	    size_t start = 0;
987	    if (str[0] == '#') {
988	      start = 1;
989	    } else if (str.size() >= 2 &&
990	               (str.compare(0, 2, "0x") == 0 || str.compare(0, 2, "0X") == 0)) {
991	      start = 2;
992	    } else {
993	      return false;
994	    }
995	    const std::string hex_part = str.substr(start);
996	    if (hex_part.empty())
997	      return false;
998	    if ((start == 1 || start == 2) && hex_part.length() != 3 &&
999	        hex_part.length() != 4 && hex_part.length() != 6 &&
1000	        hex_part.length() != 8) {
1001	      return false;
1002	    }
1003	    for (char c : hex_part) {
1004	      if (!((c >= '0' && c <= '9') || (c >= 'a' && c <= 'f') ||
1005	            (c >= 'A' && c <= 'F')))
1006	        return false;
1007	    }
1008	    out = str.substr(start).substr(0, 8);
1009	#define _2C(c) std::string(2, c)
1010	    if (out.size() == 3)
1011	      out = _2C(out[0]) + _2C(out[1]) + _2C(out[2]);
1012	    else if (out.size() == 4)
1013	      out = _2C(out[0]) + _2C(out[1]) + _2C(out[2]) + _2C(out[3]);
1014	#undef _2C
1015	    return true;
1016	  };
1017	  auto hex_color = std::string();
1018	  if (parse_color_code(color_str, hex_color)) {
1019	    value = std::stoul(hex_color, 0, 16);
1020	    if (hex_color.length() == 6)
1021	      value = (fmt != COLOR_RGBA) ? (value | 0xff000000)
1022	                                  : (((unsigned int)value << 8) | 0x000000ff);
1023	  } else {
1024	    if (!rime_api->config_get_int(config, key.c_str(), &value)) {
1025	      value = fallback;
1026	      return False;
1027	    }
1028	    if (value <= 0xffffff)
1029	      value = (fmt != COLOR_RGBA) ? (value | 0xff000000)
1030	                                  : (((unsigned int)value << 8) | 0x000000ff);
1031	    else if (value > 0xffffffff)
1032	      value &= 0xffffffff;
1033	  }
1034	  if (fmt == COLOR_ARGB)
1035	    value = ARGB2ABGR(value);
1036	  else if (fmt == COLOR_RGBA)
1037	    value = RGBA2ABGR(value);
1038	  value &= 0xffffffff;
1039	  return True;
1040	}
