1165	  };
1166	  const std::function<void(int&)> _abs = [](int& value) { value = abs(value); };
1167	  // get font faces
1168	  _RimeGetIntStr(config, "style/font_face", style.font_face, 0, 0, rmspace);
1169	  std::wstring* const pFallbackFontFace = initialize ? &style.font_face : NULL;
1170	  _RimeGetIntStr(config, "style/label_font_face", style.label_font_face, 0,
1171	                 pFallbackFontFace, rmspace);
1172	  _RimeGetIntStr(config, "style/comment_font_face", style.comment_font_face, 0,
1173	                 pFallbackFontFace, rmspace);
1174	  // able to set label font/comment font empty, force fallback to font face.
1175	  if (style.label_font_face.empty())
1176	    style.label_font_face = style.font_face;
1177	  if (style.comment_font_face.empty())
1178	    style.comment_font_face = style.font_face;
1179	  // get font points
1180	  _RimeGetIntStr(config, "style/font_point", style.font_point);
1181	  if (style.font_point <= 0)
