1184	                 "style/font_point", 0, _abs);
1185	  _RimeGetIntStr(config, "style/comment_font_point", style.comment_font_point,
1186	                 "style/font_point", 0, _abs);
1187	  _RimeGetIntStr(config, "style/candidate_abbreviate_length",
1188	                 style.candidate_abbreviate_length, 0, 0, _abs);
1189	  _RimeGetBool(config, "style/inline_preedit", initialize,
1190	               style.inline_preedit);
1191	  _RimeGetBool(config, "style/vertical_auto_reverse", initialize,
1192	               style.vertical_auto_reverse);
1193	  static constexpr Array<UIStyle::PreeditType, 3> _preeditArr = {
1194	      {{"composition", UIStyle::COMPOSITION},
1195	       {"preview", UIStyle::PREVIEW},
1196	       {"preview_all", UIStyle::PREVIEW_ALL}}};
1197	  _RimeParseStringOptWithFallback(config, "style/preedit_type",
1198	                                  style.preedit_type, _preeditArr,
1199	                                  style.preedit_type);
1200	  static constexpr Array<UIStyle::AntiAliasMode, 5> _aliasModeArr = {
1201	      {{"force_dword", UIStyle::FORCE_DWORD},
1202	       {"cleartype", UIStyle::CLEARTYPE},
1203	       {"grayscale", UIStyle::GRAYSCALE},
1204	       {"aliased", UIStyle::ALIASED},
1205	       {"default", UIStyle::DEFAULT}}};
1206	  _RimeParseStringOptWithFallback(config, "style/antialias_mode",
1207	                                  style.antialias_mode, _aliasModeArr,
1208	                                  style.antialias_mode);
1209	  static constexpr Array<UIStyle::HoverType, 3> _hoverTypeArr = {
1210	      {{"none", UIStyle::HoverType::NONE},
1211	       {"semi_hilite", UIStyle::HoverType::SEMI_HILITE},
1212	       {"hilite", UIStyle::HoverType::HILITE}}};
1213	  _RimeParseStringOptWithFallback(config, "style/hover_type", style.hover_type,
1214	                                  _hoverTypeArr, style.hover_type);
1215	  static constexpr Array<UIStyle::LayoutAlignType, 3> _alignType = {
1216	      {{"top", UIStyle::ALIGN_TOP},
1217	       {"center", UIStyle::ALIGN_CENTER},
1218	       {"bottom", UIStyle::ALIGN_BOTTOM}}};
1219	  _RimeParseStringOptWithFallback(config, "style/layout/align_type",
1220	                                  style.align_type, _alignType,
1221	                                  style.align_type);
1222	  _RimeGetBool(config, "style/display_tray_icon", initialize,
1223	               style.display_tray_icon);
1224	  _RimeGetBool(config, "style/ascii_tip_follow_cursor", initialize,
1225	               style.ascii_tip_follow_cursor);
1226	  _RimeGetBool(config, "style/horizontal", initialize, style.layout_type,
1227	               UIStyle::LAYOUT_HORIZONTAL, UIStyle::LAYOUT_VERTICAL);
1228	  _RimeGetBool(config, "style/paging_on_scroll", initialize,
1229	               style.paging_on_scroll);
1230	  _RimeGetBool(config, "style/click_to_capture", initialize,
1231	               style.click_to_capture, true, false);
1232	  _RimeGetBool(config, "style/fullscreen", false, style.layout_type,
1233	               ((style.layout_type == UIStyle::LAYOUT_HORIZONTAL)
1234	                    ? UIStyle::LAYOUT_HORIZONTAL_FULLSCREEN
1235	                    : UIStyle::LAYOUT_VERTICAL_FULLSCREEN),
1236	               style.layout_type);
1237	  _RimeGetBool(config, "style/vertical_text", false, style.layout_type,
1238	               UIStyle::LAYOUT_VERTICAL_TEXT, style.layout_type);
1239	  _RimeGetBool(config, "style/vertical_text_left_to_right", false,
1240	               style.vertical_text_left_to_right);
1241	  _RimeGetBool(config, "style/vertical_text_with_wrap", false,
1242	               style.vertical_text_with_wrap);
1243	  static constexpr Array<bool, 2> _text_orientation = {
1244	      {{"horizontal", false}, {"vertical", true}}};
1245	  bool _text_orientation_bool = false;
1246	  _RimeParseStringOptWithFallback(config, "style/text_orientation",
1247	                                  _text_orientation_bool, _text_orientation,
1248	                                  _text_orientation_bool);
1249	  if (_text_orientation_bool)
1250	    style.layout_type = UIStyle::LAYOUT_VERTICAL_TEXT;
1251	  _RimeGetIntStr(config, "style/label_format", style.label_text_format);
1252	  _RimeGetIntStr(config, "style/mark_text", style.mark_text);
1253	  _RimeGetIntStr(config, "style/layout/baseline", style.baseline, 0, 0, _abs);
1254	  _RimeGetIntStr(config, "style/layout/linespacing", style.linespacing, 0, 0,
1255	                 _abs);
1256	  _RimeGetIntStr(config, "style/layout/min_width", style.min_width, 0, 0, _abs);
1257	  _RimeGetIntStr(config, "style/layout/max_width", style.max_width, 0, 0, _abs);
1258	  _RimeGetIntStr(config, "style/layout/min_height", style.min_height, 0, 0,
1259	                 _abs);
1260	  _RimeGetIntStr(config, "style/layout/max_height", style.max_height, 0, 0,
1261	                 _abs);
1262	  // layout (alternative to style/horizontal)
1263	  static constexpr Array<UIStyle::LayoutType, 5> _layoutArr = {
1264	      {{"vertical", UIStyle::LAYOUT_VERTICAL},
1265	       {"horizontal", UIStyle::LAYOUT_HORIZONTAL},
1266	       {"vertical_text", UIStyle::LAYOUT_VERTICAL_TEXT},
1267	       {"vertical+fullscreen", UIStyle::LAYOUT_VERTICAL_FULLSCREEN},
1268	       {"horizontal+fullscreen", UIStyle::LAYOUT_HORIZONTAL_FULLSCREEN}}};
1269	  _RimeParseStringOptWithFallback(config, "style/layout/type",
1270	                                  style.layout_type, _layoutArr,
1271	                                  style.layout_type);
1272	  // disable max_width when full screen
1273	  if (style.layout_type == UIStyle::LAYOUT_HORIZONTAL_FULLSCREEN ||
1274	      style.layout_type == UIStyle::LAYOUT_VERTICAL_FULLSCREEN) {
1275	    style.max_width = 0;
1276	    style.inline_preedit = false;
1277	  }
1278	  _RimeGetIntStr(config, "style/layout/border", style.border,
1279	                 "style/layout/border_width", 0, _abs);
1280	  _RimeGetIntStr(config, "style/layout/margin_x", style.margin_x);
1281	  _RimeGetIntStr(config, "style/layout/margin_y", style.margin_y);
1282	  _RimeGetIntStr(config, "style/layout/spacing", style.spacing, 0, 0, _abs);
1283	  _RimeGetIntStr(config, "style/layout/candidate_spacing",
1284	                 style.candidate_spacing, 0, 0, _abs);
1285	  _RimeGetIntStr(config, "style/layout/hilite_spacing", style.hilite_spacing, 0,
1286	                 0, _abs);
1287	  _RimeGetIntStr(config, "style/layout/hilite_padding_x",
1288	                 style.hilite_padding_x, "style/layout/hilite_padding", 0,
1289	                 _abs);
1290	  _RimeGetIntStr(config, "style/layout/hilite_padding_y",
1291	                 style.hilite_padding_y, "style/layout/hilite_padding", 0,
1292	                 _abs);
1293	  _RimeGetIntStr(config, "style/layout/shadow_radius", style.shadow_radius, 0,
1294	                 0, _abs);
1295	  // disable shadow for fullscreen layout
1296	  style.shadow_radius *=
1297	      (!(style.layout_type == UIStyle::LAYOUT_HORIZONTAL_FULLSCREEN ||
1298	         style.layout_type == UIStyle::LAYOUT_VERTICAL_FULLSCREEN));
1299	  _RimeGetIntStr(config, "style/layout/shadow_offset_x", style.shadow_offset_x);
1300	  _RimeGetIntStr(config, "style/layout/shadow_offset_y", style.shadow_offset_y);
1301	  // round_corner as alias of hilited_corner_radius
1302	  _RimeGetIntStr(config, "style/layout/hilited_corner_radius",
1303	                 style.round_corner, "style/layout/round_corner", 0, _abs);
1304	  // corner_radius not set, fallback to round_corner
1305	  _RimeGetIntStr(config, "style/layout/corner_radius", style.round_corner_ex,
1306	                 "style/layout/round_corner", 0, _abs);
1307	  // fix padding and spacing settings
1308	  if (style.layout_type != UIStyle::LAYOUT_VERTICAL_TEXT) {
1309	    // hilite_padding vs spacing
1310	    // if hilite_padding over spacing, increase spacing
1311	    style.spacing = max(style.spacing, style.hilite_padding_y * 2);
1312	    // hilite_padding vs candidate_spacing
1313	    if (style.layout_type == UIStyle::LAYOUT_VERTICAL_FULLSCREEN ||
1314	        style.layout_type == UIStyle::LAYOUT_VERTICAL) {
1315	      // vertical, if hilite_padding_y over candidate spacing,
1316	      // increase candidate spacing
1317	      style.candidate_spacing =
1318	          max(style.candidate_spacing, style.hilite_padding_y * 2);
1319	    } else {
1320	      // horizontal, if hilite_padding_x over candidate
1321	      // spacing, increase candidate spacing
1322	      style.candidate_spacing =
1323	          max(style.candidate_spacing, style.hilite_padding_x * 2);
1324	    }
1325	    // hilite_padding_x vs hilite_spacing
1326	    if (!style.inline_preedit)
1327	      style.hilite_spacing = max(style.hilite_spacing, style.hilite_padding_x);
1328	  } else  // LAYOUT_VERTICAL_TEXT
1329	  {
1330	    // hilite_padding_x vs spacing
1331	    // if hilite_padding over spacing, increase spacing
1332	    style.spacing = max(style.spacing, style.hilite_padding_x * 2);
1333	    // hilite_padding vs candidate_spacing
1334	    // if hilite_padding_x over candidate
1335	    // spacing, increase candidate spacing
1336	    style.candidate_spacing =
1337	        max(style.candidate_spacing, style.hilite_padding_x * 2);
1338	    // vertical_text_with_wrap and hilite_padding_y over candidate_spacing
1339	    if (style.vertical_text_with_wrap)
1340	      style.candidate_spacing =
1341	          max(style.candidate_spacing, style.hilite_padding_y * 2);
1342	    // hilite_padding_y vs hilite_spacing
1343	    if (!style.inline_preedit)
1344	      style.hilite_spacing = max(style.hilite_spacing, style.hilite_padding_y);
1345	  }
1346	  // fix padding and margin settings
1347	  int scale = style.margin_x < 0 ? -1 : 1;
1348	  style.margin_x = scale * max(style.hilite_padding_x, abs(style.margin_x));
1349	  scale = style.margin_y < 0 ? -1 : 1;
1350	  style.margin_y = scale * max(style.hilite_padding_y, abs(style.margin_y));
1351	  // get enhanced_position
1352	  _RimeGetBool(config, "style/enhanced_position", initialize,
1353	               style.enhanced_position, true, false);
1354	  // get color scheme
1355	  const int BUF_SIZE = 255;
1356	  char buffer[BUF_SIZE + 1] = {0};
1357	  if (initialize && rime_api->config_get_string(config, "style/color_scheme",
1358	                                                buffer, BUF_SIZE))
1359	    _UpdateUIStyleColor(config, style);
1360	}
1361	// load color configs to style, by "style/color_scheme" or specific scheme name
1362	// "color" which is default empty
1363	static bool _UpdateUIStyleColor(RimeConfig* config,
1364	                                UIStyle& style,
1365	                                const std::string& color) {
1366	  const int BUF_SIZE = 255;
1367	  char buffer[BUF_SIZE + 1] = {0};
1368	  std::string color_mark = "style/color_scheme";
1369	  // color scheme
1370	  if (rime_api->config_get_string(config, color_mark.c_str(), buffer,
1371	                                  BUF_SIZE) ||
1372	      !color.empty()) {
1373	    std::string prefix("preset_color_schemes/");
1374	    prefix += (color.empty()) ? buffer : color;
1375	    // define color format, default abgr if not set
1376	    ColorFormat fmt = COLOR_ABGR;
1377	    static constexpr Array<ColorFormat, 3> _colorFmt = {
1378	        {{"argb", COLOR_ARGB}, {"rgba", COLOR_RGBA}, {"abgr", COLOR_ABGR}}};
1379	    _RimeParseStringOptWithFallback(config, (prefix + "/color_format").c_str(),
1380	                                    fmt, _colorFmt, COLOR_ABGR);
1381	#define COLOR(key, value, fallback) \
1382	  _RimeGetColor(config, (prefix + "/" + key), value, fmt, fallback)
1383	    COLOR("back_color", style.back_color, 0xffffffff);
1384	    COLOR("shadow_color", style.shadow_color, 0);
1385	    COLOR("prevpage_color", style.prevpage_color, 0);
1386	    COLOR("nextpage_color", style.nextpage_color, 0);
1387	    COLOR("text_color", style.text_color, 0xff000000);
1388	    COLOR("candidate_text_color", style.candidate_text_color, style.text_color);
1389	    COLOR("candidate_back_color", style.candidate_back_color, 0);
1390	    COLOR("border_color", style.border_color, style.text_color);
1391	    COLOR("hilited_text_color", style.hilited_text_color, style.text_color);
1392	    COLOR("hilited_back_color", style.hilited_back_color, style.back_color);
1393	    COLOR("hilited_candidate_text_color", style.hilited_candidate_text_color,
1394	          style.hilited_text_color);
1395	    COLOR("hilited_candidate_back_color", style.hilited_candidate_back_color,
1396	          style.hilited_back_color);
1397	    COLOR("hilited_candidate_shadow_color",
1398	          style.hilited_candidate_shadow_color, 0);
1399	    COLOR("hilited_shadow_color", style.hilited_shadow_color, 0);
1400	    COLOR("candidate_shadow_color", style.candidate_shadow_color, 0);
1401	    COLOR("candidate_border_color", style.candidate_border_color, 0);
1402	    COLOR("hilited_candidate_border_color",
1403	          style.hilited_candidate_border_color, 0);
1404	    COLOR("label_color", style.label_text_color,
1405	          blend_colors(style.candidate_text_color, style.candidate_back_color));
1406	    COLOR("hilited_label_color", style.hilited_label_text_color,
1407	          blend_colors(style.hilited_candidate_text_color,
1408	                       style.hilited_candidate_back_color));
1409	    COLOR("comment_text_color", style.comment_text_color,
1410	          style.label_text_color);
1411	    COLOR("hilited_comment_text_color", style.hilited_comment_text_color,
1412	          style.hilited_label_text_color);
1413	    COLOR("hilited_mark_color", style.hilited_mark_color, 0);
1414	#undef COLOR
1415	    return true;
1416	  }
1417	  return false;
1418	}
