1435	void RimeWithWeaselHandler::_GetStatus(Status& stat,
1436	                                       WeaselSessionId ipc_id,
1437	                                       Context& ctx) {
1438	  SessionStatus& session_status = get_session_status(ipc_id);
1439	  RimeSessionId session_id = session_status.session_id;
1440	  RIME_STRUCT(RimeStatus, status);
1441	  if (rime_api->get_status(session_id, &status)) {
1442	    std::string schema_id = "";
1443	    if (status.schema_id)
1444	      schema_id = status.schema_id;
1445	    stat.schema_name = u8tow(status.schema_name);
1446	    stat.schema_id = u8tow(status.schema_id);
1447	    stat.ascii_mode = !!status.is_ascii_mode;
1448	    stat.composing = !!status.is_composing;
1449	    stat.disabled = !!status.is_disabled;
1450	    stat.full_shape = !!status.is_full_shape;
1451	    if (schema_id != m_last_schema_id) {
1452	      session_status.__synced = false;
1453	      m_last_schema_id = schema_id;
1454	      if (schema_id != ".default") {  // don't load for schema select menu
1455	        bool inline_preedit = session_status.style.inline_preedit;
1456	        _LoadSchemaSpecificSettings(ipc_id, schema_id);
1457	        _LoadAppInlinePreeditSet(ipc_id, true);
1458	        if (session_status.style.inline_preedit != inline_preedit)
1459	          // in case of inline_preedit set in schema
1460	          _UpdateInlinePreeditStatus(ipc_id);
1461	        // refresh icon after schema changed
1462	        _RefreshTrayIcon(session_id, _UpdateUICallback);
1463	        m_ui->style() = session_status.style;
1464	        if (m_show_notifications.find("schema") != m_show_notifications.end() &&
1465	            m_show_notifications_time > 0) {
1466	          ctx.aux.str = stat.schema_name;
1467	          m_ui->Update(ctx, stat);
1468	          m_ui->ShowWithTimeout(m_show_notifications_time);
1469	        }
1470	      }
1471	    }
1472	    rime_api->free_status(&status);
1473	  }
1474	}
