1476	void RimeWithWeaselHandler::_GetContext(Context& weasel_context,
1477	                                        RimeSessionId session_id) {
1478	  RIME_STRUCT(RimeContext, ctx);
1479	  if (rime_api->get_context(session_id, &ctx)) {
1480	    if (ctx.composition.length > 0) {
1481	      weasel_context.preedit.str = u8tow(ctx.composition.preedit);
1482	      if (ctx.composition.sel_start < ctx.composition.sel_end) {
1483	        TextAttribute attr;
1484	        attr.type = HIGHLIGHTED;
1485	        attr.range.start =
1486	            utf8towcslen(ctx.composition.preedit, ctx.composition.sel_start);
1487	        attr.range.end =
1488	            utf8towcslen(ctx.composition.preedit, ctx.composition.sel_end);
1489	
1490	        weasel_context.preedit.attributes.push_back(attr);
1491	      }
1492	    }
1493	    if (ctx.menu.num_candidates) {
1494	      CandidateInfo& cinfo(weasel_context.cinfo);
1495	      _GetCandidateInfo(cinfo, ctx);
1496	    }
1497	    rime_api->free_context(&ctx);
1498	  }
1499	}
