1501	void RimeWithWeaselHandler::_UpdateInlinePreeditStatus(WeaselSessionId ipc_id) {
1502	  if (!m_ui)
1503	    return;
1504	  SessionStatus& session_status = get_session_status(ipc_id);
1505	  RimeSessionId session_id = session_status.session_id;
1506	  // set inline_preedit option
1507	  bool inline_preedit = session_status.style.inline_preedit;
1508	  rime_api->set_option(session_id, "inline_preedit", Bool(inline_preedit));
1509	  // show soft cursor on weasel panel but not inline
1510	  rime_api->set_option(session_id, "soft_cursor", Bool(!inline_preedit));
